class Resume extends Component {
  render() {
    if (this.props.data) {
      const { data } = this.props
      return (
        <section className='resume'>
          <ResumeWork data={data.work} />
          <ResumeEducation data={data.education} />
          {/* <ResumeSkills data={data.skills} /> */}
